if(window.location.hostname!=='vedic-traditions.github.io'&&window.location.hostname!=='localhost')throw new Error("Access denied");
const chertogDescriptions = {
    "7.stork": "                                               Чертог Бусла (Лелеки).\n\nЛюди, народжені під знаком Бусла (Лелеки), ніжні, в міру емоційні та поступливі. Вони завжди намагаються підтримувати порядок не лише в домі, а й у власних думках, поточних справах і особистих стосунках. За натурою вони спокійні та миролюбні, але якщо їм постійно хтось заважає досягти своїх цілей, Бусл цього не терпітиме і чинитиме гідний опір. Вони надають особливого значення сімейним цінностям, готові на самопожертву заради збереження та покращення сім'ї. Люди, які народилися в цей період, дуже працьовиті. Все, що у них є в житті, - це результат їх праці. Вони відгукливі, і за першим закликом поспішають на допомогу близьким. Вони можуть зберігати знання, тому вони можуть стати службовцями в історичних фондах або архівах, зберігачами родоводів. Особливо добре люди Чертога Бусла здатні зберегти знання і традиції свого роду, повністю передати їх наступним поколінням. Недаром Чертог названий на честь аиста - птаха, який славиться своєю вірністю дому, сім'ї, пташенятам і партнеру, що обирається раз і на все життя.\n\n                                              Чертог Бусла (Лелеки).\n\nЧертог Бусла (Лелеки) - це період, коли люди народжуються з особливим почуттям відповідальності за сім'ю і дім. Вони від природи зберігають традиції і передають їх наступним поколінням. Люди цього Чертога часто стають зберігачами родинних історій, традицій і звичаїв. Вони вміють створювати затишок і гармонію в домі. Їхня вірність сім'ї безмежна. Вони готові на все заради благополучня своїх близьких. Люди Чертога Бусла часто обирають професії, пов'язані з історією, архівами, бібліотеками, освітою. Вони мають талант до організації і планування. Вони вміють зберігати таємниці і конфіденційну інформацію. Їхнє слово для них - закон. Вони ніколи не порушують обіцянок. Люди Чертога Бусла мають високий рівень інтуїції і часто відчувають наближення небезпеки. Вони вміють адаптуватися до будь-яких ситуацій і знаходять вихід з найскладніших обставин.",
    "6.bear": "                                                 Чертог Ведмедя.\n\nЛюди, що народилися в цьому Чертозі, - добрі і уважні до оточуючих. Вони наполегливо йдуть до своєї головної мети – ушляхетнити все навколо себе. Вони вміють розпочати справу з нуля та довести її до завершення. Маючи чудову фантазію, вони можуть стати творцями, винахідниками чогось нового як у галузі науки, так і в мистецтві. Притаманні їм риси характеру - хоробрість та мужність.\nЧертог Ведмедя – той час, коли народжуються дуже позитивні, добрі люди. Їх характер, немов із ниток, зітканий із кохання, добра і турботи. Ведмідь, як ясне сонечко, може своїм появою осяяти, бо немає людини, якій він приносить зло.\nЗ дитячого віку у Ведмедів простий, легкий характер, що прагне до знань. Вони неймовірно розумні і наділені величезним потенціалом розвитку.\nДуже старанні до наук, тому здатні досягати яскравих результатів у майбутньому. Але варто врахувати - їх найголовнішим ворогом є лінь. Як і сам символ Чертога, Ведмідь вносить у характер підопічних свою відому особливість - впадати в сплячку. У людей така риса не має ознаки фізичного сну, але проявляється у періодах пасивності, коли вони можуть відкладати справи на потім. Ведмеді мають сильну волю і можуть подолати цю рису, якщо поставлять перед собою чітку мету. Вони вміють працювати в команді і часто стають лідерами. Вони мають талант до навчання інших і можуть бути чудовими наставниками. Люди Чертога Ведмедя мають високий рівень емпатії і розуміння емоцій інших людей. Вони вміють прощати і забувати образи. Вони мають сильне почуття справедливості і завжди готові захистити слабких. Вони мають талант до творчості і можуть досягти успіху в мистецтві, науці, бізнесі. Вони вміють знаходити компроміси і вирішувати конфлікти мирним шляхом.",
    "10.bull": "                                               Чертог Тура (Бика).\n\nЧертог Тура - знак Сварожого кола, що увібрав всю мудрість і спокій тварини Тура (Бика), який дав чертогу своє ім'я. Над народженими під знаком Тура панує і дбає бог Кришень. Цей бог зберігає Всесвітню вікову Мудрість, Верховний план буття. Під заступництвом Кришеня знаходяться всі арійські та слов'янські обряди, від нього передаються людям знання про прикмети – закони взаємодії матерії в Яві. А надихає своїм духом дерево Осина – дерево руйнування зла, поглинання негативної енергії. Люди цього періоду - ідеалісти за світоглядом, мають підвищене почуття відповідальності. Їх відрізняє підвищена працездатність, але захоплюючись творінням, вони часто забувають про рідних і близьких. Ці люди можуть багато чого досягти, оскільки мають завидним упорством і працьовитістю. Вони здатні щось винаходити, проектувати різні механізми.\nТури, як і тварина, що дає їм назву, неймовірно наполегливі і працьовиті. Вони ніколи не поспішають, але в той же час вкрай вдумливо і обережно рухаються до наміченої мети. Турам своєрідний спокій і впевненість у своїх діях. Вони мають сильну волю і можуть подолати будь-які перешкоди на шляху до мети. Вони вміють планувати і організовувати свою роботу. Вони мають талант до лідерства і можуть стати чудовими керівниками. Люди Чертога Тура мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття відповідальності і завжди виконують свої обіцянки. Вони вміють працювати в команді і досягати спільних цілей. Вони мають талант до навчання інших і можуть бути чудовими наставниками.",
    "15.white leopard": "                                               Чертог Раса (Рись, Білий Леопард).\n\n\nЛюдей чертога Раса (Рисі, Білого Леопарда) відрізняє цілеспрямованість та розважливість. Однак при цьому вони не завжди здатні брати до уваги думку іншої людини. Вони можуть цінувати те, що дано зверху. Ці люди з раннього дитинства усвідомлюють свою особливу силу та унікальність. Однак вони не повинні забувати про шанобливе ставлення до Бога і матері-природи, які, власне, і є для них головним джерелом життя та енергії. Разом із веселою вдачею та безтурботністю люди Чертога Раса проявляють спокій і розважливість у момент розгляду важливих питань.\nЧоловіки, що народилися Чертоге Раса, відповідально ставляться до своїх робочих обов'язків, вони прагнуть виконувати все якісно і точно вчасно. Їм можна довірити вирішення будь-яких завдань, вони зроблять максимум і обов'язково досягнуть поставлених цілей. Для них немає непереборних перешкод, це стійкі і відважні люди. Від'ємною рисою деяких чоловіків Чертога Раса є егоїстичне ставлення до оточуючих. Вони можуть в це час бути надмірно вимогливими і не помічати потреб інших людей. Жінки Чертога Раса мають сильний характер і вольовий характер. Вони вміють досягати своїх цілей і не здаються перед труднощами. Вони мають високий рівень інтелекту і можуть досягти успіху в кар'єрі. Вони вміють поєднувати кар'єру і сім'ю. Вони мають талант до творчості і можуть бути успішними в мистецтві, літературі, науці. Вони мають сильне почуття справедливості і завжди готові захистити слабких. Вони вміють прощати і забувати образи. Вони мають високий рівень емпатії і розуміння емоцій інших людей.",
    "12.falcon": "                                                Чертог Фініста.\n\nЧертог Фініста – знак у зодіакальній системі праслов'ян. Своє ім'я отримав на честь міфологічного птаха Фініста, який був символом відродження, вічної молодості та безсмертя. У слов'янських казках цей птах носив ім'я Фініст-Ясний Сокіл. Його описували, як птаха з палаючим оперенням червоного і вогненно-золотого кольору, якого неможливо було вбити, у нього була властивість знову відроджуватися з попелу і перемагати будь-яку підлість, зло і чаклунство. Іноді цей міфічний персонаж міг приймати образ молодого хлопця, який приходив у Явь і захищав пригноблених і ображених людей. Повертав їм віру в добро і справедливість. Ім'я Фініст-ясний сокіл у слов'янській міфології пов'язується з молодою людиною напівбожественного походження, яка завжди з'являлася в найгостріші моменти нещасть і нападів ворогів. Ці риси - активність, боротьба за справедливість, принциповість, твердість у своїх принципах, а разом з тим неймовірне життєлюбство і добре розвинений гумор, діляться народженим під знаком Фініста. Вони, як та міфічний птах, мають здатність відроджуватися після важких випробувань і ставати сильнішими. Люди Чертога Фініста мають високий рівень енергії і ентузіазму. Вони вміють надихати інших і вести їх за собою. Вони мають талант до лідерства і можуть стати чудовими керівниками. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові захистити слабких. Вони вміють прощати і забувати образи. Вони мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють працювати в команді і досягати спільних цілей.",
    "14.eagle": "                                               Чертог Орла.\n\nУ людей Чертога Орла сильно розвинене почуття заступництва і доброзичливість. Ці люди не виявляють слабкості, вони рішучі, особливо коли чітко планують план своїх дій. Вони вміють відбити будь-які атаки: чи то словесні випади на їхню адресу, чи фізичні дії, спрямовані проти них. Людям Чертога Орла корисно займатися практиками на оволодіння силою як у духовній частині, так і у фізичній. Орел вже народжується зі свідомістю своїх сил. Причому це стосується не тільки фізичних, а й інтелектуальних здібностей. Любознайливі діти цього Чертога з молодих нігтів схильні до пристрастей пізнання світобудови. Іми керує ненаситне бажання дізнатися природу походження будь-яких явищ і предметів. Чертог Орла рухає своїх підопічних до нових відкриттів. Орли мають вроджені лідерські якості, але при цьому у них немає місця високомір'ю і високомір'ю. Будучи прикладом сміливості і великодушності, вони з радістю прийдуть на допомогу страждаючим. Рідкістю для них буває така риса, як меркантильність. Орел не вважає за потрібне відмовлятися від своїх принципів заради матеріальної вигоди. Люди Чертога Орла мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові захистити слабких. Вони вміють працювати в команді і досягати спільних цілей. Вони мають талант до навчання інших і можуть бути чудовими наставниками. Вони мають високий рівень енергії і ентузіазму. Вони вміють надихати інших і вести їх за собою.",
    "2.pike": "Чертог Щуки.\nЧертог Щуки увібрав у себе заступництво відразу двох богородиць: Рожани - богині сімейного достатку та Щуки - цариці річкової та матері водяного духу. Мудрість Одночасно двох божеств займається людьми цього чертога і вносить у характер риси розважливості, доброти і просвітлення. Чертог Щуки отримав свою назву на честь прабатька всього річкового світу.\nОбраз Щуки-чарівниці зберігся до наших часів у міфах і переказах. Широко відома казка про Ємелю та Щуку, яка виконує бажання – яскравий приклад народних оповідей.\nЛюдям, що народилися в цей період, властиве прагнення до спокійної, розміреного життя. Основна складність для них - прийняти важливе рішення. Однак до нових і несподіваних обставин вони легко пристосовуються. Люди Чертога Щуки мають здатність ладити з дітьми, вони добре розуміють поведінку малюків, їхні вчинки і бажання. Гармонія у всьому - в побуті, в душі і свідомості - до цього прагнуть ті, хто з'явився на світ у період Чертога Щуки.\nОднак, при всіх своїх перевагах іноді вони можуть бути наївними, надмірно довірливими. Їм слід бути обережнішими у виборі друзів і партнерів. Люди Чертога Щуки мають високий рівень інтуїції і часто відчувають наближення небезпеки. Вони вміють адаптуватися до будь-яких ситуацій і знаходять вихід з найскладніших обставин. Вони мають талант до творчості і можуть досягти успіху в мистецтві, літературі, науці. Вони вміють працювати в команді і досягати спільних цілей. Вони мають сильне почуття справедливості і завжди готові допомогти тим, хто потребує. Вони вміють прощати і забувати образи. Вони мають високий рівень емпатії і розуміння емоцій інших людей.",
    "1.boar": "                                                        Чертог Вепря.\n\n У цей час народжуються допитливі та наполегливі люди. Їх відрізняє цілеспрямованість та вміння долати перешкоди. Недоліком є здатність не брати до уваги інтереси інших людей. При цьому вони намагаються бути справедливими та рішучими, наполегливо доносити до інших вірність своїх суджень. Вони звикли досягати наміченого, але можуть допускати надто вільну, розкуту поведінку, якщо не будуть тримати себе в руках. Людям Чертога Вепря завжди слід пам'ятати про силу Небесних Законів. Так само як Вепр - символ відваги і сміливості, народжені в цей час ставали неординарними людьми. Їх внутрішня сила була важливою частиною їх характеристики. Навіть якщо зовні людині не дані розміри велетня, то упорство і цілеспрямованість завжди виділяють їх з натовпу.\nЧертог Вепря перш за все наділяє підопічного силою духу. Вепри, всупереч своєму грозному покровителю, є достатньо добрими і миролюбними створіннями. Їм не властиво нападати першими або бити в спину. Вепр - це скоріше символ захисту, ніж нападу. Люди Чертога Вепря мають сильну волю і можуть подолати будь-які перешкоди на шляху до мети. Вони вміють працювати в команді і часто стають лідерами. Вони мають талант до навчання інших і можуть бути чудовими наставниками. Вони мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові захистити слабких. Вони вміють прощати і забувати образи. Вони мають високий рівень енергії і ентузіазму. Вони вміють надихати інших і вести їх за собою.",
    "3.swan": "                                               Чертог Лебедя.\n\nПредставникам цього Чертога, як правило, властива унікальна душевна організація, але також їх відрізняє і завидне працьовитість. Вони завжди розраховують тільки на себе і не покладаються на удачу. Крім того, вони мають здатність проникати в таємниці Долі як своєї, так і інших людей. Вони успішують у землеробстві, вкладають всю душу в свою нелегку працю. Віддають перевагу традиційному життєвому укладу, розміреному і спокійному. Але не завжди вміють приймати рішення. Звичайно, чого не відняти - це мудрість і проникливий розум Лебедя. Від їх прискіпливого і спостережливого погляду не зможе сховатися жодна дрібниця. Вони помічають все, що відбувається, але не завжди вимовляють вголос свої висновки. Чертог Лебедя наділяє людину прагненням до влади, вмінням співпереживати і розуміти чужий біль. Вважається, що люди, народжені в Чертозі Лебедя, мають унікальний дар «зріти в корінь» будь-якої ситуації.\nЛебеді мають відмінними організаторськими здібностями, їм важливо упорядковувати навколишнє середовище, робити його зручним і розумним. Їм подобається, коли все має своє місце і порядок. Люди Чертога Лебедя мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові допомогти тим, хто потребує. Вони вміють працювати в команді і досягати спільних цілей. Вони мають талант до творчості і можуть бути успішними в мистецтві, літературі, науці. Вони мають високий рівень інтуїції і часто відчувають наближення небезпеки. Вони вміють адаптуватися до будь-яких ситуацій і знаходять вихід з найскладніших обставин.",
    "4.snake": "                                                Чертог Змія.\n\nНародження в Чертозі Змія передбачає людині світлу, яскраву долю. Представники Чертога Змія відрізняються неймовірною активністю, що спрямовується виключно на добрі справи. Рідко коли побачиш людей-змій, що сидять на одному місці і довго роздумують про високі матерії Вони знаходяться в постійному русі, яке залежно від ситуації і життєвих обставин може бути хаотичним або упорядкованим. Відмінна риса людей цього періоду - мудрість. Однак у деяких ситуаціях вони схильні проявляти егоїзм і консерватизм. Народжені в Чертозі Змія дуже комунікабельні, можуть досягти хороших результатів в інформаційній сфері. Також досягають успіху і поваги в сфері знань, завдяки вмінню знайти в собі мудрість сил вогню.\nПредставники Чертога Змія в любові зазвичай розбираються краще за інших. Вони трепетно вихваляють високе почуття, що проявляється в їх ніжному і дбайливому ставленні до свого обранця. В любов вони готові зануритися з головою, але вимагають такої самовіддачі від партнера. Якщо Змії помітять, що коханий не відповідає взаємністю, вони можуть стати дуже роздратованими і навіть ворожими. Люди Чертога Змія мають високий рівень енергії і ентузіазму. Вони вміють надихати інших і вести їх за собою. Вони мають талант до лідерства і можуть стати чудовими керівниками. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові захистити слабких. Вони вміють працювати в команді і досягати спільних цілей.",
    "5.crow": "                                              Чертог Ворона.\n\nЧас Ворона - це період зимового сонцестояння, коли зима сковує всі земні чертоги, природа замирає і готується битва за відродження Яві. Для слов'ян, так само як і для інших давніх народів, ці дні мали сакральне значення - переможе Світло або Темрява, почне додаватися сонячний день. Чертог Ворона названий на честь речі птаха, символу мудрості і хранителя таємниць. Саме ці якості найбільш простежуються у людей, народжених під час Ворона - вони мудрі, спокійні і цілеспрямовані. Ще час Ворона знаходиться під владою бога Коляди. Для слов'ян це час очікування - переможе світло, почне додаватися день, зменшиться зимовий морок, або гряде відродження Весни. Чертог Ворона - час великої битви Темряви і Світла за владу в Яві. Це час, коли бог Коляда перевертає коло, по якому йде Сонце. Ім'я Коляди має походження від слова коло. Тобто формально Коляда той, хто веде Сонце по колу, змінює день і ніч, зиму і літо.\nЛюди, народжені в цьому Чертозі, неординарні, добрі і приємні в спілкуванні. Дуже часто вони не можуть налагодити відносини з оточуючими через свою надмірну вимогливість. Люди Чертога Ворона мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові допомогти тим, хто потребує. Вони вміють працювати в команді і досягати спільних цілей. Вони мають талант до творчості і можуть бути успішними в мистецтві, літературі, науці. Вони мають високий рівень інтуїції і часто відчувають наближення небезпеки. Вони вміють адаптуватися до будь-яких ситуацій і знаходять вихід з найскладніших обставин.",
    "8.wolf": "                                               Чертог Вовка.\n\nВовкам може бути властива жорсткість, але не жорстокість. Вовки обережні, але не агресивні. Інтроверти, завжди віддадуть перевагу своєму близькому колу або самотності - галасливим компаніям. Будуть ухилятися від конфлікту, поки не станеться справжня загроза.\nНападати на Вовків - собі дорожче, з ними потрібно жити в мирі. Тоді вони будуть найкращими товаришами.\nВовкам властива рішучість, але вони завжди обережні і часто з презирством ставляться до людей без внутрішнього стержня. Вони схильні ідеалізувати оточуючих людей, а тому часто розчаровуються у невірності і легковажності людей.\nВовкам властива вірність у стосунках. Чоловіки вовки відважні, іноді безрозсудні, на перший погляд, але вони завжди знають, чого хочуть. Жінки-вовки рідко бувають старими дівами, в основному, вони завжди з партнером.\nНароджені в чертозі Вовка можуть працювати лікарями, поліцейськими, служити в армії, вони - хороші і чесні журналісти, які поважають факти.\nБог-покровитель Вовка - Велес, дає їм багато умінь в області землеробства, ведення домашнього господарства. Так само з них отримуються чудові батьки і матері. Люди Чертога Вовка мають високий рівень лояльності і відданості. Вони вміють захищати своїх близьких і друзів. Вони мають сильне почуття справедливості і завжди готові допомогти тим, хто потребує. Вони вміють працювати в команді і досягати спільних цілей. Вони мають талант до навчання інших і можуть бути чудовими наставниками.",
    "9.fox": "                                               Чертог Лисиці.\n\nЧертог Лисиці володарює в той час, коли весна вступає в свої права - це час загибелі демона Зими і відродження, пробудження духу Весни. У момент весняного рівнодення відбувається чаклунство - відступає Темрява, даючи можливість світлому дню стати довшим. Чертог Лисиці отримав назву на честь символу хитрості, розуму, краси і перетворення. Вважалося, що лисиця своїми хитрими хитрощами допомагає духу Весни увійти в права і зміцніти, перемігши сутінки зимового часу.\nЛисиця в слов'янській міфології - персонаж, обдарований неймовірним розумом, здатністю перетворення, хитрістю.\nПри цьому він не має чіткого розмежування на позитивне або негативне значення героя. Лисицю поважали, при цьому побоювалися стати жертвою її проказ. Чертог Лисиці вносить у характер людини унікальну властивість пластичності. Лисиці можуть досягати різного становища в суспільстві, потрапляти в будь-які ситуації, але що ні відняти - завжди вирвуться, вивернуть все собі на користь. Ця людина неймовірно розумна, прозорлива, цілеспрямована. Народжені в цьому Чертозі вміють знаходити вихід з будь-якої ситуації. Вони мають високий рівень адаптації і можуть працювати в будь-якій сфері. Люди Чертога Лисиці мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові допомогти тим, хто потребує. Вони вміють працювати в команді і досягати спільних цілей. Вони мають талант до творчості і можуть бути успішними в мистецтві, літературі, науці.",
    "11.elk": "                                               Чертог Лося.\n\nЧертог Лося не випадково отримав у покровителі богиню Ладу - праматір більшості слов'янських богів і велику захисницю всіх слов'янських племен і родів. Весняне сонце вже повністю увійшло в свою силу, природа розцвіла і відродилася у всій красі - той час, коли царять обі берегині - Лада і Мати-лосиха. Чертог Лося отримав свою назву на честь лісового духу, великої і всесильної володарки звірів Матері-лосихи.\nБудучи символом лісового світу, він може стати привітливим для доброї людини або жорстоко покарати того, хто прийшов з поганими намірами. У владі Матері-лосихи проявити милість і допомогти лісовим дарам мисливцю, що заблудився в пошуках здобичі.Але якщо людина прийшла вбивати в ліс ради забави, то мати-лосиха може навлечь покарання, заплутавши-закрутивши в лісі, вбивши беззахисного на розтерзання хижим звірам.\nВажливою особливістю, що відрізняє Сваржий коло від своїх пізніших аналогів-гороскопів, є божественна сила, що дає допомогу кожному знаку. Чертог Лося знаходиться під покровительством богині-богородиці Лади, а підростає його дерево - Ялина. Люди Чертога Лося мають високий рівень відповідальності і турботи про оточуючих. Вони вміють захищати своїх близьких і друзів. Вони мають сильне почуття справедливості і завжди готові допомогти тим, хто потребує. Вони вміють працювати в команді і досягати спільних цілей. Вони мають талант до навчання інших і можуть бути чудовими наставниками. Вони мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми.",
    "13.horse": "                                               Чертог Коня.\n\nЧертог коня - дивовижний час, коли активізуються сили різних вимірів. Пік розквіту природних сил і період літнього сонцестояння, коли сонце і солярні духи, що дають енергію життя, панують у Яві в повну силу. Чертог Лошаді - час природної сили і пік розквіту всіх стихій. Кінь - символ сили, швидкості, плодородності, працьовитості. Він уособлює значення молодої і сильної енергії життя. Цей Чертог символізує значення чоловічої енергетики, вже не юнацької вдали, а дорослої сили, коли пора обрати дружину собі і зробити потомство. Літо, коли всі Чертоги святкують силу Сонця - час величайшого плодородія землі. Це час, коли боги Прави приходили на землю, щоб дарувати блага і виконання бажань людям. Люди, що народилися в цей період, мають уміння легко справлятися з різними неприємностями і ударами Долі. Часто з них виходять відмінні керівники. Вони здатні легко поєднувати воєдино те, що іншим дається з великими труднощами. Їм подобається процес інтеграції в житті, науці і роботі. Вони люблять земний світ і насолоджуються ним. Люди Чертога Коня мають високий рівень енергії і ентузіазму. Вони вміють надихати інших і вести їх за собою. Вони мають талант до лідерства і можуть стати чудовими керівниками. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові допомогти тим, хто потребує. Вони вміють працювати в команді і досягати спільних цілей.",
    "16.virgo": "                                               Чертог Діви.\n\nЦе єдиний Чертог, названий не на честь звіра або птаха, а присвячений образу людини, його духу (джива - санскрит). Але це не випадково, бо людина є частиною природи і має своє місце в програмі світобудови. Без людини Ява (Життя) не мала б сенсу, вона вершина божого задуму. Чертог Діви - знак людей, які прийшли на землю бачити. Їхнє вище призначення зводиться до того, що після них на землі в Яві повинні залишатися плоди праці, думки, матеріальні блага. Тому небеса даровали покровителям цього Чертога ті сутності, які дають силу і натхнення в розвиток і множення.\nДжива своєю божественною силою множить могутність духу, а дерево яблуня як натхненник надає прагненням людини матеріальну орієнтацію. Тому серед Дів високий відсоток дуже організованих, логічно мислячих представників, які всіма силами націлені будувати і бачити. Люди, народжені в цьому Чертозі, дуже цілеспрямовані. Вони прагнуть пізнавати світ, проявляють лідерські якості і впертість. Ці люди мають усіма якостями лідера, але при цьому вони дуже вимогливі до себе. Вони мають високий рівень інтелекту і можуть досягти успіху в науці, техніці, бізнесі. Вони вміють знаходити нестандартні рішення і вирішувати складні проблеми. Вони мають сильне почуття справедливості і завжди готові допомогти тим, хто потребує. Вони вміють працювати в команді і досягати спільних цілей. Вони мають талант до творчості і можуть бути успішними в мистецтві, літературі, науці. Вони мають високий рівень дисципліни і організації."
};
const chertogs=[{id:"16.virgo",name:"Чертог Діви",start:[8,27],end:[9,20]},{id:"1.boar",name:"Чертог Вепра",start:[9,20],end:[10,11]},{id:"2.pike",name:"Чертог Щуки",start:[10,11],end:[11,3]},{id:"3.swan",name:"Чертог Лебедя",start:[11,3],end:[11,24]},{id:"4.snake",name:"Чертог Змія",start:[11,24],end:[12,16]},{id:"5.crow",name:"Чертог Ворона",start:[12,16],end:[1,7]},{id:"6.bear",name:"Чертог Ведмедя",start:[1,7],end:[1,31]},{id:"7.stork",name:"Чертог Лелеки (Бусла)",start:[1,31],end:[2,25]},{id:"8.wolf",name:"Чертог Вовка",start:[2,25],end:[3,22]},{id:"9.fox",name:"Чертог Лисиці",start:[3,22],end:[4,14]},{id:"10.bull",name:"Чертог Тура (Бика)",start:[4,14],end:[5,6]},{id:"11.elk",name:"Чертог Лося",start:[5,6],end:[5,29]},{id:"12.falcon",name:"Чертог Фініста (Сокола)",start:[5,29],end:[6,20]},{id:"13.horse",name:"Чертог Коня",start:[6,20],end:[7,13]},{id:"14.eagle",name:"Чертог Орла",start:[7,13],end:[8,4]},{id:"15.white leopard",name:"Чертог Раса (білого леопарда)",start:[8,4],end:[8,27]}];
function init(){const grid=document.getElementById("grid");chertogs.forEach(c=>{const item=document.createElement("div");item.className="chertog-item";item.id="item-"+c.id;item.onclick=()=>openModal(c.id);const img=document.createElement("img");img.className="chertog-img";img.src="chertogs/"+c.id+".webp";img.alt=c.name;img.title=c.name;item.appendChild(img);grid.appendChild(item)})}
function isInChertog(m,d,c){let sm=c.start[0],sd=c.start[1];let em=c.end[0],ed=c.end[1];if(sm===em){return m===sm&&d>=sd&&d<=ed}else if(sm<em){if(m===sm&&d>=sd)return true;if(m===em&&d<=ed)return true;if(m>sm&&m<em)return true;return false}else{if(m===sm&&d>=sd)return true;if(m===em&&d<=ed)return true;if(m>sm||m<em)return true;return false}}
function calculateChertog(){const val=document.getElementById("birthDate").value;if(!val)return;const date=new Date(val);const m=date.getMonth()+1;const d=date.getDate();const activeIds=[];const activeNames=[];for(let i=0;i<chertogs.length;i++){const c=chertogs[i];const el=document.getElementById("item-"+c.id);el.classList.remove("active");if(isInChertog(m,d,c)){activeIds.push(c.id);activeNames.push(c.name);el.classList.add("active");setTimeout(()=>{el.scrollIntoView({behavior:'smooth',block:'center'})},100)}}const resultDiv=document.getElementById("result");if(activeIds.length>0){if(activeIds.length>1){resultDiv.innerText="Ви знаходитесь на межі: "+activeNames.join(" та ")}else{resultDiv.innerText="Ваш чертог: "+activeNames[0]}}else{resultDiv.innerText=""}}
function openModal(id){const modal=document.getElementById("modal");const modalImg=document.getElementById("modalImg");const modalText=document.getElementById("modalText");modalImg.src="chertogs/"+id+".webp";let desc=chertogDescriptions[id]||"Опис тимчасово недоступний.";desc=desc.replace(/\n\s*\n/g,'\n\n');const godNames={"1.boar":"Рамхата","2.pike":"Рожани","3.swan":"Макоші","4.snake":"Семаргла","5.crow":"Коляди","6.bear":"Сварога","7.stork":"Рода","8.wolf":"Велеса","9.fox":"Марени","10.bull":"Кришеня","11.elk":"Лади","12.falcon":"Вишеня","13.horse":"Купали","14.eagle":"Перуна","15.white leopard":"Тарха","16.virgo":"Дживи"};const chertogData=chertogs.find(c=>c.id===id);modalText.textContent=desc;modal.classList.add("visible");document.body.style.overflow="hidden"}
function closeModal(){document.getElementById("modal").classList.remove("visible");document.body.style.overflow="auto"}
let bgMusic=null;const audioControl=document.getElementById('audioControl');const audioIconOn=document.getElementById('audioIconOn');const audioIconOff=document.getElementById('audioIconOff');const TARGET_VOLUME=0.4;const FADE_IN_DURATION=2000;const FADE_OUT_DURATION=1500;let audioStarted=false;let isMuted=false;let isPlaying=false;let fadeInterval=null;
function fadeVolume(targetVolume,duration,callback){if(!bgMusic)return;if(fadeInterval){clearInterval(fadeInterval);fadeInterval=null}const startVolume=bgMusic.volume||0;const volumeDiff=targetVolume-startVolume;const steps=60;const stepTime=duration/steps;let currentStep=0;fadeInterval=setInterval(()=>{currentStep++;const progress=currentStep/steps;const easeProgress=1-Math.pow(1-progress,3);bgMusic.volume=Math.max(0,Math.min(1,startVolume+volumeDiff*easeProgress));if(currentStep>=steps){clearInterval(fadeInterval);fadeInterval=null;bgMusic.volume=targetVolume;if(callback)callback()}},stepTime)}
function startAudioOnFirstClick(){if(audioStarted)return;audioStarted=true;bgMusic=new Audio('slavetnodark.mp3');bgMusic.loop=true;bgMusic.volume=0;bgMusic.load();const playPromise=bgMusic.play();if(playPromise!==undefined){playPromise.then(()=>{isPlaying=true;isMuted=false;fadeVolume(TARGET_VOLUME,FADE_IN_DURATION);updateAudioIcon()}).catch(err=>{console.log('Audio playback failed:',err);audioStarted=false})}document.removeEventListener('click',startAudioOnFirstClick,true);document.removeEventListener('touchstart',startAudioOnFirstClick,true);document.removeEventListener('keydown',startAudioOnFirstClick,true)}
document.addEventListener('click',startAudioOnFirstClick,true);document.addEventListener('touchstart',startAudioOnFirstClick,true);document.addEventListener('keydown',startAudioOnFirstClick,true);
if(audioControl){audioControl.addEventListener('click',e=>{e.stopPropagation();if(!audioStarted){startAudioOnFirstClick();return}isMuted=!isMuted;if(isMuted){bgMusic.muted=true;audioControl.classList.add('muted');audioIconOn.style.display='none';audioIconOff.style.display='block'}else{bgMusic.muted=false;audioControl.classList.remove('muted');audioIconOn.style.display='block';audioIconOff.style.display='none'}})}
function updateAudioIcon(){if(isMuted){audioControl.classList.add('muted');audioIconOn.style.display='none';audioIconOff.style.display='block'}else{audioControl.classList.remove('muted');audioIconOn.style.display='block';audioIconOff.style.display='none'}}
function handleOrderLinkClick(e){const link=e.currentTarget;const href=link.getAttribute('href');if(audioStarted&&bgMusic&&href&&href!=='#'){e.preventDefault();fadeVolume(0,FADE_OUT_DURATION,()=>{window.location.href=href})}}
const originalOpenModal=openModal;openModal=function(id){originalOpenModal(id);setTimeout(()=>{const shopLinks=document.querySelectorAll('.shop-link');shopLinks.forEach(link=>{link.removeEventListener('click',handleOrderLinkClick);link.addEventListener('click',handleOrderLinkClick)})},100)};
window.onload=function(){if(typeof init==='function')init();flatpickr("#birthDate",{locale:{weekdays:{shorthand:["Нд","Пн","Вт","Ср","Чт","Пт","Сб"],longhand:["Неділя","Понеділок","Вівторок","Середа","Четвер","П'ятниця","Субота"]},months:{shorthand:["Січ","Лют","Бер","Кві","Тра","Чер","Лип","Сер","Вер","Жов","Лис","Гру"],longhand:["Січень","Лютий","Березень","Квітень","Травень","Червень","Липень","Серпень","Вересень","Жовтень","Листопад","Грудень"]},firstDayOfWeek:1,rangeSeparator:" — ",weekAbbreviation:"Тиж.",scrollTitle:"Прокрутіть для збільшення",toggleTitle:"Натисніть для перемикання",amPM:["ДП","ПП"],yearAriaLabel:"Рік",monthAriaLabel:"Місяць",hourAriaLabel:"Година",minuteAriaLabel:"Хвилина",time_24hr:true},dateFormat:"Y-m-d",altInput:true,altFormat:"d.m.Y",allowInput:true,disableMobile:true})};
